      "method": "GET",
      "endpoint": "/api/v1/attendance",
      "parameters": ["user_id", "month", "year"]
    },
    {
      "name": "get_leave_balance",
      "description": "Call this when user asks about leaves, remaining leave days, sick leave, casual leave, or any leave balance",
      "method": "GET",
      "endpoint": "/api/v1/leaves/balance",
      "parameters": ["user_id"]
    },
    {
      "name": "get_holidays",
      "description": "Call this when user asks about upcoming holidays, public holidays, or whether a specific day is a holiday",
      "method": "GET",
      "endpoint": "/api/v1/holidays",
      "parameters": ["year", "month"]
    }
  ]
}

